def log_request_response(f):
    """Decorator to log requests and responses"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # Log request
        request_start_time = time.time()
        request_id = f"{datetime.now().strftime('%Y%m%d%H%M%S%f')}"
        
        g.request_id = request_id
        
        # Log request details
        logger.info(
            f"REQUEST - ID: {request_id} | "
            f"Method: {request.method} | "
            f"URL: {request.url} | "
            f"Headers: {dict(request.headers)} | "
            f"Body: {request.get_data(as_text=True) if request.get_data() else 'None'} | "
            f"Remote Addr: {request.remote_addr}"
        )
        
        try:
            # Execute the function
            result = f(*args, **kwargs)
            
            # Log response
            response_time = time.time() - request_start_time
            logger.info(
                f"RESPONSE - ID: {request_id} | "
                f"Status: {getattr(result, 'status_code', 'N/A')} | "
                f"Response Time: {response_time:.3f}s"
            )
            
            return result
            
        except Exception as e:
            # Log error
            response_time = time.time() - request_start_time
            logger.error(
                f"ERROR - ID: {request_id} | "
                f"Exception: {str(e)} | "
                f"Response Time: {response_time:.3f}s"
            )
            raise
            
    return decorated_function

def authenticate(f):
    """Authentication decorator"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth = request.authorization
        if not auth or not auth.username or not auth.password:
            logger.warning(
                f"AUTH FAILED - No credentials provided | "
                f"Remote Addr: {request.remote_addr}"
            )
            return jsonify({'error': 'Authentication required'}), 401
            
        # Check user credentials (in production, use database lookup)
        if auth.username in users:
            # In production, use proper password verification
            if check_password_hash(users[auth.username]['password_hash'], auth.password):
                logger.info(
                    f"AUTH SUCCESS - User: {auth.username} | "
                    f"Remote Addr: {request.remote_addr}"
                )
                return f(*args, **kwargs)
            else:
                logger.warning(
                    f"AUTH FAILED - Invalid password | "
                    f"User: {auth.username} | "
                    f"Remote Addr: {request.remote_addr}"
                )
                return jsonify({'error': 'Invalid credentials'}), 401
        else:
            logger.warning(
                f"AUTH FAILED - User not found | "
                f"User: {auth.username} | "
                f"Remote Addr: {request.remote_addr}"
            )
            return jsonify({'error': 'Invalid credentials'}), 401
            
    return decorated_function

